import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface Profile {
  username: string;
  followers: number;
  engagementRate: number;
}

interface GrowthTrend {
  month: string;
  followersGained: number;
}

interface SocialMediaStatsData {
  profile: Profile;
  growthTrend: GrowthTrend[];
  monthlyGrowth: number[];
}

export default function Widget() {
  const socialMediaData = response.data as SocialMediaStatsData;
  const { profile, growthTrend } = socialMediaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              {profile.username}
            </Typography>
            <Typography variant="h4" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
              {profile.followers.toLocaleString()} Followers
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Engagement Rate: {profile.engagementRate}%
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: growthTrend.map(g => g.followersGained),
                  color: '#1DA1F2',
                  label: 'Followers Gained',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: growthTrend.map(g => g.month),
                  id: 'months',
                },
              ]}
              yAxis={[{ id: 'followersGained' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsYAxis
                axisId="followersGained"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
